// Bicep: enforce naming convention via a module parameter + local variable

// naming.bicep — reusable naming module
@description('Workload abbreviation (e.g. payments, identity, shared)')
param workload string

@description('Environment abbreviation')
@allowed(['dev', 'test', 'staging', 'prod'])
param environment string

@description('Azure region abbreviation (e.g. eastus, westeu, ause)')
param regionAbbr string

@description('Three-digit sequence number')
param sequence string = '001'

// Resource type prefixes — adjust to your organization's standard
var prefixes = {
  vm: 'vm'
  vnet: 'vnet'
  subnet: 'snet'
  nsg: 'nsg'
  pip: 'pip'
  lb: 'lb'
  kv: 'kv'
  sa: 'st'          // storage: no hyphens, no prefix separator
  rg: 'rg'
  aks: 'aks'
  acr: 'acr'
  apim: 'apim'
  func: 'func'
}

// Standard pattern: {type}-{workload}-{env}-{region}-{seq}
// Storage exception: {st}{workload}{env}{region} (no hyphens, max 24 chars)
output names object = {
  vm:     '${prefixes.vm}-${workload}-${environment}-${regionAbbr}-${sequence}'
  vnet:   '${prefixes.vnet}-${workload}-${environment}-${regionAbbr}'
  nsg:    '${prefixes.nsg}-${workload}-${environment}-${regionAbbr}'
  rg:     '${prefixes.rg}-${workload}-${environment}-${regionAbbr}'
  kv:     '${prefixes.kv}-${workload}-${environment}-${regionAbbr}'
  // Storage: max 24 chars, no hyphens, lowercase only
  sa:     '${prefixes.sa}${workload}${environment}${regionAbbr}'
  // AKS cluster name
  aks:    '${prefixes.aks}-${workload}-${environment}-${regionAbbr}'
}

// main.bicep — consume the naming module
module naming 'naming.bicep' = {
  name: 'naming'
  params: {
    workload: 'payments'
    environment: 'prod'
    regionAbbr: 'eastus'
    sequence: '001'
  }
}

resource vm 'Microsoft.Compute/virtualMachines@2024-03-01' = {
  name: naming.outputs.names.vm    // 'vm-payments-prod-eastus-001'
  location: resourceGroup().location
  // ...
}

resource kv 'Microsoft.KeyVault/vaults@2023-07-01' = {
  name: naming.outputs.names.kv    // 'kv-payments-prod-eastus'
  location: resourceGroup().location
  // ...
}

# Terraform: enforce naming convention via locals and a naming module

# naming.tf — local variables that compute all resource names
locals {
  workload    = var.workload
  environment = var.environment
  region      = var.region_abbreviation
  sequence    = format("%03d", var.sequence)

  names = {
    resource_group   = "rg-${local.workload}-${local.environment}-${local.region}"
    virtual_network  = "vnet-${local.workload}-${local.environment}-${local.region}"
    subnet_app       = "snet-${local.workload}-app-${local.environment}-${local.region}"
    subnet_data      = "snet-${local.workload}-data-${local.environment}-${local.region}"
    nsg_app          = "nsg-${local.workload}-app-${local.environment}-${local.region}"
    virtual_machine  = "vm-${local.workload}-${local.environment}-${local.region}-${local.sequence}"
    # Storage: no hyphens, max 24 chars, globally unique suffix via random
    storage_account  = "st${local.workload}${local.environment}${local.region}${var.storage_suffix}"
    key_vault        = "kv-${local.workload}-${local.environment}-${local.region}"
    aks_cluster      = "aks-${local.workload}-${local.environment}-${local.region}"
  }
}

# variables.tf
variable "workload" {
  type        = string
  description = "Workload abbreviation (e.g. 'payments', 'catalog', 'identity')"
  validation {
    condition     = can(regex("^[a-z0-9]+$", var.workload))
    error_message = "workload must be lowercase alphanumeric only"
  }
}

variable "environment" {
  type    = string
  validation {
    condition     = contains(["dev", "test", "staging", "prod"], var.environment)
    error_message = "environment must be one of: dev, test, staging, prod"
  }
}

variable "region_abbreviation" {
  type        = string
  description = "Short region code (e.g. 'eastus', 'westeu', 'ause')"
}

variable "sequence" {
  type    = number
  default = 1
}

variable "storage_suffix" {
  type        = string
  description = "Short random suffix to guarantee global uniqueness of storage account"
  default     = ""
}

# main.tf — consume the local names
resource "azurerm_resource_group" "main" {
  name     = local.names.resource_group
  location = var.location
}

resource "azurerm_virtual_network" "main" {
  name                = local.names.virtual_network
  resource_group_name = azurerm_resource_group.main.name
  location            = var.location
  address_space       = ["10.0.0.0/16"]
}

resource "azurerm_key_vault" "main" {
  name                = local.names.key_vault
  resource_group_name = azurerm_resource_group.main.name
  location            = var.location
  tenant_id           = data.azurerm_client_config.current.tenant_id
  sku_name            = "standard"
}

# Azure Policy: Deny deployments that violate naming conventions
# Uses 'match' condition which supports wildcard pattern matching

# 1. Create a custom policy definition for VM naming
az policy definition create \
  --name 'require-vm-naming-convention' \
  --display-name 'Require VM naming convention: vm-{workload}-{env}-{region}-{seq}' \
  --description 'Deny VM deployments whose names do not match the pattern vm-*-*-*-[0-9][0-9][0-9]' \
  --mode All \
  --rules '{
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.Compute/virtualMachines"},
        {"not": {"field": "name", "match": "vm-????-????-???????-###"}}
      ]
    },
    "then": {"effect": "Deny"}
  }' \
  --management-group mg-corp

# Azure Policy match wildcards:
#   ? = any single character
#   * = any sequence of characters
#   # = any single digit

# 2. Create policy definition for storage account naming (no hyphens, prefix st)
az policy definition create \
  --name 'require-storage-naming-convention' \
  --display-name 'Require storage account naming: st{workload}{env}{region}' \
  --mode All \
  --rules '{
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.Storage/storageAccounts"},
        {"not": {"field": "name", "match": "st*"}}
      ]
    },
    "then": {"effect": "Deny"}
  }' \
  --management-group mg-corp

# 3. Assign both policies at the management group scope
az policy assignment create \
  --name 'enforce-naming-conventions' \
  --display-name 'Enforce resource naming conventions' \
  --policy-set-definition 'naming-convention-initiative' \
  --scope '/providers/Microsoft.Management/managementGroups/mg-corp' \
  --enforcement-mode Default

# Policy Deny means: az resource create will fail at the ARM layer
# with a message: 'Resource was disallowed by policy: require-vm-naming-convention'

// ARM / Bicep: name validation using policy-safe patterns
// When Policy Deny is in place, ARM validates names before resource creation.
// The Bicep below shows the minimal parameter contract for a naming-compliant VM.

param location string = resourceGroup().location

@description('Workload name (lowercase alphanumeric, max 12 chars)')
@maxLength(12)
param workload string

@allowed(['dev', 'test', 'staging', 'prod'])
param environment string

@description('Region abbreviation matching your naming standard (e.g. eastus, westeu)')
param regionAbbr string

@description('Three-digit sequence as a string')
@minLength(3)
@maxLength(3)
param sequence string = '001'

// Derive names from parameters — no hardcoded strings in the template body
var vmName  = 'vm-${workload}-${environment}-${regionAbbr}-${sequence}'
var rgName  = 'rg-${workload}-${environment}-${regionAbbr}'
var vnetName = 'vnet-${workload}-${environment}-${regionAbbr}'
var nsgName  = 'nsg-${workload}-${environment}-${regionAbbr}'

// Storage account: no hyphens, prefix st, max 24 chars
// Truncate workload to 8 chars to stay under 24 with the fixed segments
var saWorkload = length(workload) > 8 ? substring(workload, 0, 8) : workload
var saName = 'st${saWorkload}${environment}${take(regionAbbr, 3)}'

// Outputs for use by consuming templates
output names object = {
  vm: vmName
  rg: rgName
  vnet: vnetName
  nsg: nsgName
  sa: saName
}

// Usage example in a parent template:
// module naming 'naming.bicep' = {
//   name: 'naming'
//   params: { workload: 'payments', environment: 'prod', regionAbbr: 'eastus' }
// }
// var n = naming.outputs.names
// resource vm 'Microsoft.Compute/virtualMachines@2024-03-01' = { name: n.vm ... }
